SELECT AVG(average_score) AS average_analysis_score
FROM survey_analysis
WHERE analysis_type = 'overall';

SELECT COUNT(*) 
FROM feedback_forms 
WHERE form_status = 'published';

SELECT num_participants
FROM tour_sessions
WHERE session_id = 0 AND session_date = '2023-07-10';

SELECT expertise, COUNT(DISTINCT guide_id) AS num_guides
FROM tour_guides
GROUP BY expertise;

SELECT created_date, COUNT(*) AS total_forms_created
FROM feedback_forms
GROUP BY created_date;

SELECT tour_id, SUM(num_participants) AS total_participants
FROM tour_sessions
GROUP BY tour_id;

SELECT created_date
FROM feedback_forms
WHERE form_status = 'draft' AND is_template = 1;

SELECT question_id, AVG(average_score) AS avg_score, COUNT(question_id) AS total_responses
FROM survey_analysis
GROUP BY question_id;

SELECT session_id, SUM(num_participants) AS total_participants
FROM tour_sessions
GROUP BY session_id;
